  Future<PaymentResult> _invokeNativeWalletFlow({
    required String walletType,
    required double amount,
    required String currency,
    required Map<String, dynamic> paymentData,
    String? orderId,
  }) async {
    try {
      final channel = MethodChannel('secure_payment_wallet');
      final response = await channel.invokeMapMethod<String, dynamic>('startWalletPayment', <String, dynamic>{
        'walletType': walletType,
        'amount': amount,
        'currency': currency,
        'paymentData': _sanitizePaymentData(paymentData),
        'orderId': orderId,
        'environment': describeEnum(config.environment),
      });

      if (response == null) {
        return const PaymentResult(status: PaymentStatus.error, message: 'No wallet response');
      }

      final status = _mapNativeStatus(response['status']?.toString());
      return PaymentResult(
        status: status,
        transactionId: response['transactionId']?.toString(),
        orderId: response['orderId']?.toString(),
        message: response['message']?.toString(),
        metadata: response,
