        status: PaymentStatus.error,
        message: 'Wallet payment error',
        metadata: {'error': e.toString()},
      );
    }
  }

  void _handlePurchaseUpdates(List<PurchaseDetails> purchaseDetailsList) async {
    for (final purchase in purchaseDetailsList) {
      _logger.log('purchase update', data: {
        'productId': purchase.productID,
        'status': purchase.status.toString(),
        'pendingCompletePurchase': purchase.pendingCompletePurchase,
      });

      switch (purchase.status) {
        case PurchaseStatus.pending:
          _resultController.add(const PaymentResult(status: PaymentStatus.pending, message: 'Purchase pending'));
          break;
        case PurchaseStatus.purchased:
        case PurchaseStatus.restored:
          try {
            final receipt = await _extractReceipt(purchase);
            if (config.verifyReceiptsServerSide) {
              final verification = await gatewayClient.verifyReceipt(
                provider: _providerName,
                receiptData: receipt,
                productId: purchase.productID,
                transactionId: purchase.purchaseID ?? purchase.productID,
                userId: _hashedUserId(purchase.productID),
              );
              _resultController.add(PaymentResult(
                status: purchase.status == PurchaseStatus.purchased ? PaymentStatus.purchased : PaymentStatus.restored,
                transactionId: purchase.purchaseID,
                message: verification['message']?.toString(),
                metadata: verification,
              ));
            } else {
              _resultController.add(PaymentResult(
                status: purchase.status == PurchaseStatus.purchased ? PaymentStatus.purchased : PaymentStatus.restored,
                transactionId: purchase.purchaseID,
                message: 'Purchase completed',
              ));
            }
          } catch (e) {
            _resultController.add(PaymentResult(
              status: PaymentStatus.failed,
              transactionId: purchase.purchaseID,
              message: 'Receipt verification failed',
              metadata: {'error': e.toString()},
            ));
          }
          break;
        case PurchaseStatus.error:
          _resultController.add(PaymentResult(
            status: PaymentStatus.failed,
            transactionId: purchase.purchaseID,
            message: purchase.error?.message ?? 'Purchase failed',
            metadata: {'code': purchase.error?.code},
          ));
          break;
        case PurchaseStatus.canceled:
          _resultController.add(const PaymentResult(
            status: PaymentStatus.cancelled,
            message: 'Purchase cancelled',
          ));
          break;
        case PurchaseStatus.restored:
          break;
      }

      if (purchase.pendingCompletePurchase) {
        await _iap.completePurchase(purchase);
      }
    }
  }

  Future<String> _extractReceipt(PurchaseDetails purchase) async {
    if (purchase is AppStorePurchaseDetails) {
      return purchase.verificationData.serverVerificationData;
    }
    if (purchase is GooglePlayPurchaseDetails) {
      return purchase.verificationData.serverVerificationData;
    }
    return purchase.verificationData.serverVerificationData;
  }

  String _hashedUserId(String userId) {
    final bytes = utf8.encode('${config.apiKey}:$userId');
    return sha256.convert(bytes).toString();
  }

  double _parsePrice(String price) {
    final cleaned = price.replaceAll(RegExp(r'[^0-9.,]'), '').replaceAll(',', '.');
    return double.tryParse(cleaned) ?? 0.0;
  }

  String get _providerName {
    if (Platform.isIOS) return 'apple';
    if (Platform.isAndroid) return 'google';
    return 'unknown';
  }

  PaymentStatus _mapNativeStatus(String? status) {
    switch (status?.toLowerCase()) {
      case 'success':
      case 'succeeded':
      case 'paid':
        return PaymentStatus.purchased;
      case 'pending':
        return PaymentStatus.pending;
      case 'cancelled':
      case 'canceled':
        return PaymentStatus.cancelled;
      case 'failed':
        return PaymentStatus.failed;
      default:
        return PaymentStatus.error;
    }
  }

  Map<String, dynamic> _sanitizePaymentData(Map<String, dynamic> input) {
    final output = <String, dynamic>{};
    input.forEach((key, value) {
      if (RegExp(r'(card|cvv|cvc|pan|token|secret|password)', caseSensitive: false).hasMatch(key)) {
        output[key] = '***';
      } else if (value is Map<String, dynamic>) {
        output[key] = _sanitizePaymentData(value);
      } else if (value is List) {
        output[key] = value.map((e) => e is Map<String, dynamic> ? _sanitizePaymentData(e) : e).toList();
      } else {
        output[key] = value;
      }
    });
    return output;
  }

  void dispose() {
    _purchaseSub?.cancel();
    _resultController.close();
    gatewayClient.dispose();
  }
}

class PaymentModule {
  final PaymentService service;

  PaymentModule._(this.service);

  static Future<PaymentModule> initialize(PaymentConfig config) async {
    final gatewayClient = PaymentGatewayClient(config);
    final service = PaymentService(config: config, gatewayClient: gatewayClient);
    await service.initialize();
    return PaymentModule._(service);
  }
}

class PaymentController extends ChangeNotifier {
  final PaymentService service;
  PaymentStatus status = PaymentStatus.idle;
  String? message;
  PaymentResult? lastResult;
  StreamSubscription<PaymentResult>? _sub;

  PaymentController(this.service) {
    _sub = service.results.listen((result) {
      lastResult = result;
      status = result.status;
      message = result.message;
      notifyListeners();
    });
  }

  Future<List<ProductDetails>> loadProducts(Set<String> ids) async {
    status = PaymentStatus.loading;
    notifyListeners();
    return service.fetchProducts(ids);
  }

  Future<PaymentResult> purchase({
    required ProductDetails product,
    required String userId,
    bool consumable = false,
    Map<String, dynamic>? metadata,
  }) async {
    status = PaymentStatus.loading;
    notifyListeners();
    final result = consumable
        ? await service.buyConsumable(product: product, userId: userId, metadata: metadata)
        : await service.buyProduct(product: product, userId: userId, metadata: metadata);
    lastResult = result;
    status = result.status;
    message = result.message;
    notifyListeners();
    return result;
  }

  Future<PaymentResult> walletPay({
    required String walletType,
    required String userId,
    required double amount,
    required String currency,
    required Map<String, dynamic> paymentData,
    Map<String, dynamic>? metadata,
  }) async {
    status = PaymentStatus.loading;
    notifyListeners();
    final result = await service.processWalletPayment(
      walletType: walletType,
      userId: userId,
      amount: amount,
      currency: currency,
      paymentData: paymentData,
      metadata: metadata,
    );
    lastResult = result;
    status = result.status;
    message = result.message;
    notifyListeners();
    return result;
  }

  Future<void> restore({required String userId}) async {
    status = PaymentStatus.loading;
    notifyListeners();
    final result = await service.restorePurchases(userId: userId);
    lastResult = result;
    status = result.status;
    message = result.message;
    notifyListeners();
  }

  @override
  void dispose() {
    _sub?.cancel();
    super.dispose();
  }
}

class PaymentSecurity {
  static bool validateEnvironment(PaymentEnvironment environment) {
    if (kReleaseMode && environment == PaymentEnvironment.sandbox) return true;
    return true;
  }

  static String generateNonce([int length = 32]) {
    final random = List<int>.generate(length, (i) => (DateTime.now().microsecondsSinceEpoch + i * 31) % 256);
    return base64UrlEncode(random);
  }

  static String signPayload(String payload, String secret) {
    final hmacSha256 = Hmac(sha256, utf8.encode(secret));
    return hmacSha256.convert(utf8.encode(payload)).toString();
  }

  static bool isSensitiveField(String key) {
    return RegExp(r'(card|cvv|cvc|pan|token|secret|password|receipt|signature)', caseSensitive: false).hasMatch(key);
  }
}